import React, { useState, useEffect, useRef } from "react";
import { motion, useInView } from "framer-motion";
import "./index.css";

export default function App() {
  const [theme, setTheme] = useState("dark");

  const toggleTheme = () => {
    setTheme(theme === "dark" ? "light" : "dark");
  };

  return (
    <div
      className={`${theme === "dark"
        ? "bg-gradient-to-br from-black via-gray-900 to-black text-white"
        : "bg-gradient-to-br from-gray-100 via-gray-200 to-gray-50 text-gray-900"
        } min-h-screen transition-all duration-500`}
    >
      <Navbar toggleTheme={toggleTheme} />
      <Hero />
      <Stats />
      <Skills />
      <Experience theme={theme} />
      <Projects theme={theme} />
      <Contact />
      <Footer />
    </div>
  );
}

// NAVBAR
function Navbar({ toggleTheme }) {
  return (
    <div className="sticky top-0 z-50 backdrop-blur-xl bg-white/5 border-b border-white/10">
      <div className="max-w-7xl mx-auto flex justify-between items-center px-6 py-4">
        <h1 className="text-xl font-bold tracking-widest">Muhammad Kashif</h1>

        <div className="hidden md:flex gap-8 text-sm tracking-wide">
          <a href="#exp" className="hover:text-blue-400 transition">Experience</a>
          <a href="#projects" className="hover:text-blue-400 transition">Projects</a>
          <a href="#contact" className="hover:text-blue-400 transition">Contact</a>
        </div>

        <button onClick={toggleTheme} className="px-3 py-1 border rounded-lg hover:scale-105 transition">
          Toggle
        </button>
      </div>
    </div>
  );
}

// HERO
function Hero() {
  return (
    <div className="text-center py-32 relative overflow-hidden">
      <motion.h1
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        className="text-6xl font-bold bg-gradient-to-r from-blue-400 via-purple-500 to-pink-500 text-transparent bg-clip-text"
      >
        Muhammad Kashif
      </motion.h1>

      <p className="mt-6 text-xl text-gray-400">
        Full Stack Engineer | Real-Time Systems Specialist
      </p>

      <div className="mt-8 flex justify-center gap-4">
        <a href="#projects"><button className="px-6 py-2 bg-blue-600 rounded-xl hover:scale-105 transition">Projects</button></a>
        <a href="#contact"><button className="px-6 py-2 border rounded-xl hover:scale-105 transition">Contact</button></a>
      </div>

      <div className="mt-6 flex justify-center gap-4">
        <a href="#" target="_blank"><button className="px-4 py-2 border rounded-xl hover:bg-blue-600/20 transition">LinkedIn</button></a>
        <a href="#" target="_blank"><button className="px-4 py-2 border rounded-xl hover:bg-purple-600/20 transition">GitHub</button></a>
      </div>
    </div>
  );
}

// COUNT UP
function useCountUp(end, duration = 1500, start) {
  const [count, setCount] = useState(0);

  useEffect(() => {
    if (!start) return;
    let startVal = 0;
    const step = end / (duration / 16);

    const timer = setInterval(() => {
      startVal += step;
      if (startVal >= end) {
        setCount(end);
        clearInterval(timer);
      } else {
        setCount(Math.floor(startVal));
      }
    }, 16);

    return () => clearInterval(timer);
  }, [start, end, duration]);

  return count;
}

// STATS
function Stats() {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true });

  const years = useCountUp(3, 1500, inView);
  const projects = useCountUp(12, 1500, inView);

  return (
    <div ref={ref} className="py-20 text-center">
      <div className="flex justify-center gap-16 flex-wrap">
        {[{ value: years + "+", label: "Years Experience" },
        { value: projects + "+", label: "Projects" },
        { value: "Expert", label: "Real-Time Systems" }].map((item, i) => (
          <div key={i} className="group">
            <h2 className="text-5xl font-bold group-hover:scale-110 transition">{item.value}</h2>
            <p className="text-gray-400">{item.label}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

// SKILLS
function Skills() {
  const skills = ["React", "Node.js", "WebSockets", "MongoDB", "Leaflet", "C", "C++", "WebGL"];

  return (
    <div className="py-20 text-center">
      <h2 className="text-3xl font-bold mb-10">Skills</h2>
      <div className="flex justify-center gap-4 flex-wrap">
        {skills.map((skill, i) => (
          <motion.span
            whileHover={{ scale: 1.1 }}
            key={i}
            className="px-5 py-2 border rounded-full bg-white/5 backdrop-blur-lg"
          >
            {skill}
          </motion.span>
        ))}
      </div>
    </div>
  );
}

// EXPERIENCE
function Experience({ theme }) {
  return (
    <div id="exp" className="px-10 py-24">
      <h2 className="text-4xl font-bold mb-16 text-center">Experience</h2>

      <div className="max-w-6xl mx-auto grid md:grid-cols-2 gap-10">
        {["Air Traffic & Sensors", "Full Stack Apps"].map((title, i) => (
          <motion.div
            key={i}
            initial={{ opacity: 0, y: 50 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            className="p-8 rounded-3xl backdrop-blur-xl border bg-white/5 hover:scale-105 transition shadow-2xl"
          >
